internal actual fun maybeNewCrossfadePainter(
    previous: AsyncImagePainter.State,
    current: AsyncImagePainter.State,
    contentScale: ContentScale,
): CrossfadePainter? {
    // We can only invoke the transition factory if the state is success or error.
    val result = when (current) {
        is AsyncImagePainter.State.Success -> current.result
        is AsyncImagePainter.State.Error -> current.result
        else -> return null
    }

    // Invoke the transition factory and wrap the painter in a `CrossfadePainter` if it returns
    // a `CrossfadeTransformation`.
    val transition = result.request.transitionFactory.create(FakeTransitionTarget, result)
    if (transition is CrossfadeTransition) {
        return CrossfadePainter(
            start = previous.painter.takeIf { previous is AsyncImagePainter.State.Loading },
            end = current.painter,
            contentScale = contentScale,
            duration = transition.durationMillis.milliseconds,
            fadeStart = result !is SuccessResult || !result.isPlaceholderCached,
            preferExactIntrinsicSize = transition.preferExactIntrinsicSize,
            preferEndFirstIntrinsicSize = result.request.preferEndFirstIntrinsicSize,
        )
    } else {
        return null
    }
}

internal fun SerialDescriptor.extractParameters(index: Int): ProtoDesc {
    val annotations = getElementAnnotations(index)
    var protoId: Int = index + 1
    var format: ProtoIntegerType = ProtoIntegerType.DEFAULT
    var protoPacked = false
    var isOneOf = false

    for (i in annotations.indices) { // Allocation-friendly loop
        val annotation = annotations[i]
        if (annotation is ProtoNumber) {
            protoId = annotation.number
            checkFieldNumber(protoId, i, this)
        } else if (annotation is ProtoType) {
            format = annotation.type
        } else if (annotation is ProtoPacked) {
            protoPacked = true
        } else if (annotation is ProtoOneOf) {
            isOneOf = true
        }
    }
    if (isOneOf) {
        // reset protoId to index-based for oneOf field,
        // Decoder will restore the real proto id then from [ProtobufDecoder.index2IdMap]
        // See [kotlinx.serialization.protobuf.internal.ProtobufDecoder.decodeElementIndex] for detail
        protoId = index + 1
    }
    return ProtoDesc(protoId, format, protoPacked, isOneOf)
}

private fun StringBuilder.generateListType(messageType: TypeDefinition, index: Int): List<TypeDefinition> {
    val messageDescriptor = messageType.descriptor
    val collectionDescriptor = messageDescriptor.getElementDescriptor(index)
    val originalElementDescriptor = collectionDescriptor.getElementDescriptor(0)
    val elementType = if (collectionDescriptor.kind == StructureKind.LIST) {
        if (originalElementDescriptor.isProtobufCollection) {
            createNestedCollectionType(messageType, index, originalElementDescriptor, "nested collection in list")
        } else {
            TypeDefinition(originalElementDescriptor)
        }
    } else {
        createLegacyMapType(messageType, index, "legacy map")
    }

    val elementDescriptor = elementType.descriptor

    if (elementDescriptor.isNullable) {
        appendLine("  // WARNING: nullable elements of collections can not be represented in protobuf")
    }
    generateCollectionAbsenceComment(messageDescriptor, collectionDescriptor, index)

    val typeName = elementDescriptor.protobufTypeName(messageDescriptor.getElementAnnotations(index))
    append("  repeated ").append(typeName)

    return if (elementDescriptor.isProtobufMessageOrEnum) {
        listOf(elementType)
    } else {
        emptyList()
    }
}

@InternalAPI
    public fun install(client: HttpClient) {
        client.sendPipeline.intercept(HttpSendPipeline.Engine) { content ->
            val builder = HttpRequestBuilder().apply {
                takeFromWithExecutionContext(context)
                setBody(content)
            }

            client.monitor.raise(HttpRequestIsReadyForSending, builder)

            val requestData = builder.build().apply {
                attributes.put(CLIENT_CONFIG, client.config)
            }

            validateHeaders(requestData)
            checkExtensions(requestData)

            val responseData = executeWithinCallContext(requestData)
            val call = HttpClientCall(client, requestData, responseData)

            val response = call.response
            client.monitor.raise(HttpResponseReceived, response)

            response.coroutineContext.job.invokeOnCompletion {
                if (it != null) {
                    client.monitor.raise(HttpResponseCancelled, response)
                }
            }

            proceedWith(call)
        }
    }

internal fun buildPipeline(): ApplicationCallPipeline = cachedPipeline ?: run {
    var current: RoutingNode? = this
    val pipeline = ApplicationCallPipeline(developmentMode, application.environment)
    val routePipelines = mutableListOf<ApplicationCallPipeline>()
    while (current != null) {
        routePipelines.add(current)
        current = current.parent
    }

    for (index in routePipelines.lastIndex downTo 0) {
        val routePipeline = routePipelines[index]
        pipeline.merge(routePipeline)
        pipeline.receivePipeline.merge(routePipeline.receivePipeline)
        pipeline.sendPipeline.merge(routePipeline.sendPipeline)
    }

    val handlers = handlers
    for (index in 0..handlers.lastIndex) {
        pipeline.intercept(Call) {
            val call = call as RoutingPipelineCall
            val routingCall = RoutingCall(call)
            val routingContext = RoutingContext(routingCall)
            if (call.isHandled) return@intercept
            handlers[index].invoke(routingContext)
        }
    }
    cachedPipeline = pipeline
    pipeline
}

private fun asyncService(request: HttpServletRequest, response: HttpServletResponse) {
    val asyncContext = request.startAsync()!!.apply {
        timeout = 0L
    }

    launch(Dispatchers.IO) {
        val call = AsyncServletApplicationCall(
            application,
            request,
            response,
            engineContext = Dispatchers.IO,
            userContext = Dispatchers.IO,
            upgrade = upgrade,
            parentCoroutineContext = coroutineContext,
            managedByEngineHeaders
        )

        try {
            enginePipeline.execute(call)
        } catch (cause: Throwable) {
            logError(call, cause)
            response.sendErrorIfNotCommitted(cause.message)
        } finally {
            try {
                asyncContext.complete()
            } catch (alreadyCompleted: IllegalStateException) {
                application.log.debug(
                    "AsyncContext is already completed due to previous I/O error",
                    alreadyCompleted
                )
            }
        }
    }
}

